<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">repomix</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --remote</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yamadashy/repomix</span></span>
